    function formatPlatformLabel(platform) { const value = String(platform || '').trim().toLowerCase(); if (!value) return tr('unknown'); if (value === 'windows') return 'Windows'; if (value === 'mac' || value === 'macos' || value === 'darwin') return 'macOS'; if (value === 'linux' || value === 'linxu') return 'Linux'; return value.charAt(0).toUpperCase() + value.slice(1); }
