    function findMailPreset(provider) { return MAIL_PRESETS[provider] || MAIL_PRESETS.custom; }
    function detectMailProvider(cfg) { const host = String(cfg?.smtp_host || '').trim().toLowerCase(); const port = Number(cfg?.smtp_port || 0); const encryption = String(cfg?.smtp_encryption || '').trim().toLowerCase(); for (const [provider, preset] of Object.entries(MAIL_PRESETS)) { if (provider === 'custom') continue; if (host === preset.smtp_host && (!port || port === preset.smtp_port) && (!encryption || encryption === preset.smtp_encryption)) return provider; } return String(cfg?.provider || '').trim() || 'custom'; }
    function renderMailConfig(cfg = {}) { const provider = detectMailProvider(cfg); document.getElementById('mailProvider').value = MAIL_PRESETS[provider] ? provider : 'custom'; document.getElementById('mailHost').value = cfg.smtp_host || ''; document.getElementById('mailPort').value = cfg.smtp_port ? String(cfg.smtp_port) : ''; document.getElementById('mailEncryption').value = cfg.smtp_encryption || 'auto'; document.getElementById('mailUsername').value = cfg.smtp_username || ''; document.getElementById('mailPassword').value = cfg.smtp_password || ''; document.getElementById('mailFromName').value = cfg.from_name || 'CodeClaw Hub'; document.getElementById('mailFromEmail').value = cfg.from_email || cfg.smtp_username || ''; }
    function applyMailPreset() { const provider = document.getElementById('mailProvider').value; const preset = findMailPreset(provider); if (provider !== 'custom') { document.getElementById('mailHost').value = preset.smtp_host || ''; document.getElementById('mailPort').value = preset.smtp_port ? String(preset.smtp_port) : ''; document.getElementById('mailEncryption').value = preset.smtp_encryption || 'auto'; if (!document.getElementById('mailFromEmail').value.trim()) document.getElementById('mailFromEmail').value = document.getElementById('mailUsername').value.trim(); } }
    function collectMailConfig() { const host = document.getElementById('mailHost').value.trim(); const username = document.getElementById('mailUsername').value.trim(); const password = document.getElementById('mailPassword').value; const fromEmail = document.getElementById('mailFromEmail').value.trim(); const provider = document.getElementById('mailProvider').value || 'custom'; if (!host || !username || !password || !fromEmail) throw new Error('Please complete the SMTP host, account, password, and sender email first.'); const parsedPort = Number(document.getElementById('mailPort').value || 0); return { enabled: true, provider, smtp_host: host, smtp_port: parsedPort > 0 ? parsedPort : findMailPreset(provider).smtp_port || 587, smtp_encryption: document.getElementById('mailEncryption').value || 'auto', smtp_username: username, smtp_password: password, from_name: document.getElementById('mailFromName').value.trim() || 'CodeClaw Hub', from_email: fromEmail }; }
    async function loadMailConfig() { try { const data = await api('/api/admin/mail/config'); renderMailConfig(data || {}); } catch (err) { const msg = tr('mailConfigLoadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function saveMailConfig() { try { const payload = collectMailConfig(); const data = await api('/api/admin/mail/config', { method: 'POST', body: JSON.stringify(payload) }); renderMailConfig(data || payload); const msg = tr('mailConfigSaved'); setOutput(msg); showToast(msg, 'success'); return data || payload; } catch (err) { const msg = tr('mailConfigSaveFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); throw err; } }
    function renderMachineList(items) { machineItemsCache = Array.isArray(items) ? items : []; document.getElementById('machineCountHero').textContent = String(machineItemsCache.length); const root = document.getElementById('machines'); const pager = document.getElementById('machinesPager'); const pagerMeta = document.getElementById('machinesPagerMeta'); const prevButton = document.getElementById('machinesPrevButton'); const nextButton = document.getElementById('machinesNextButton'); const header = `<div class="row header"><div>${tr('machine')}</div><div>${ml('boundEmail')}</div><div>${ml('runtime')}</div><div>${ml('heartbeat')}</div><div>${tr('status')}</div><div>${tr('lastSeen')}</div><div>${ml('actions')}</div></div>`; if (!machineItemsCache.length) { pager.classList.add('hidden'); root.innerHTML = header + '<div class="hint">' + tr('noMachinesLoaded') + '</div>'; return; } const totalPages = Math.max(1, Math.ceil(machineItemsCache.length / machinePageSize)); if (machinePage > totalPages) machinePage = totalPages; if (machinePage < 1) machinePage = 1; const startIndex = (machinePage - 1) * machinePageSize; const pageItems = machineItemsCache.slice(startIndex, startIndex + machinePageSize); root.innerHTML = header + pageItems.map(v => { const state = v.status === 'online' ? tr('online') : v.status === 'offline' ? tr('offline') : (v.status || tr('unknown')); const email = v.user_email || tr('na'); const runtime = [`${formatPlatformLabel(v.platform)}`, v.hostname ? `${ml('host')}: ${v.hostname}` : '', v.arch ? `${ml('arch')}: ${v.arch}` : '', v.app_version ? `${ml('version')}: ${v.app_version}` : ''].filter(Boolean); const heartbeat = [v.heartbeat_interval_sec ? `${ml('interval')}: ${v.heartbeat_interval_sec}s` : '', typeof v.active_sessions === 'number' ? `${ml('activeSessions')}: ${v.active_sessions}` : ''].filter(Boolean); const isOnline = v.online || v.status === 'online'; const deleteBtn = isOnline ? '' : `<button class="btn-danger" style="height:32px;font-size:12px;padding:0 10px" onclick="deleteMachine('${v.machine_id}')">${ml('deleteMachine')}</button>`; return `<div class="row"><div><strong>${v.name || v.machine_id || tr('machine')}</strong><div class="item-meta mono">${v.machine_id || ''}</div></div><div><div>${email}</div><div class="item-meta mono">${v.user_id || ''}</div></div><div>${runtime.map(line => `<div class="item-meta">${line}</div>`).join('')}</div><div>${heartbeat.length ? heartbeat.map(line => `<div class="item-meta">${line}</div>`).join('') : `<div class="item-meta">${tr('na')}</div>`}</div><div><span class="badge ${(isOnline ? 'ok' : 'warn')}">${state}</span></div><div>${v.last_seen_at || tr('na')}</div><div>${deleteBtn}</div></div>`; }).join(''); const start = startIndex + 1; const end = startIndex + pageItems.length; pagerMeta.textContent = totalPages > 1 ? ml('pageSummary').replace('{start}', String(start)).replace('{end}', String(end)).replace('{total}', String(machineItemsCache.length)) : ml('pageSingle').replace('{total}', String(machineItemsCache.length)); prevButton.disabled = machinePage <= 1; nextButton.disabled = machinePage >= totalPages; pager.classList.toggle('hidden', machineItemsCache.length <= machinePageSize); }
    function changeMachinesPage(step) { const totalPages = Math.max(1, Math.ceil(machineItemsCache.length / machinePageSize)); machinePage = Math.min(totalPages, Math.max(1, machinePage + step)); renderMachineList(machineItemsCache); }
