    async function clearOfflineMachines() { if (!confirm(ml('clearOfflineConfirm'))) return; try { const data = await api('/api/admin/machines/clear-offline', { method: 'POST' }); const msg = ml('clearSuccess').replace('{count}', String(data.cleared || 0)); setOutput(msg); showToast(msg, 'success'); await loadMachines(); } catch (err) { const msg = ml('clearFailed').replace('{error}', err.message); setOutput(msg); showToast(msg, 'error'); } }
    async function sendTestMail() { try { const email = document.getElementById('testMailEmail').value.trim(); if (!email) { const msg = currentLang === 'zh' ? '??????????' : 'Please enter a test recipient email.'; setOutput(msg); showToast(msg, 'error'); return; } await saveMailConfig(); const data = await api('/api/admin/mail/test', { method: 'POST', body: JSON.stringify({ email }) }); const msg = data.message || tr('mailSent'); setOutput(msg); showToast(msg, 'success'); } catch (err) { const msg = tr('mailFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function changeAdminPassword() { const currentPassword = document.getElementById('currentPasswordInput').value; const newPassword = document.getElementById('newPasswordInput').value; const confirmPassword = document.getElementById('confirmPasswordInput').value; if (!currentPassword || !newPassword) { const msg = tr('requestFailed'); setOutput(msg); showToast(msg, 'error'); return; } if (newPassword !== confirmPassword) { const msg = ptr('mismatch'); setOutput(msg); showToast(msg, 'error'); return; } try { const data = await api('/api/admin/password', { method: 'POST', body: JSON.stringify({ current_password: currentPassword, new_password: newPassword }) }); if (data.access_token) localStorage.setItem(adminTokenKey, data.access_token); if (data.admin) localStorage.setItem(adminProfileKey, JSON.stringify(data.admin)); document.getElementById('currentPasswordInput').value = ''; document.getElementById('newPasswordInput').value = ''; document.getElementById('confirmPasswordInput').value = ''; refreshAdminHeader(); const msg = ptr('changed'); setOutput(msg); showToast(msg, 'success'); } catch (err) { setOutput(err.message); showToast(err.message, 'error'); } }
    async function updateAdminProfile() { const email = document.getElementById('adminEmailInput').value.trim(); if (!email) { const msg = prf('required'); setOutput(msg); showToast(msg, 'error'); return; } try { const data = await api('/api/admin/profile', { method: 'POST', body: JSON.stringify({ email }) }); if (data.access_token) localStorage.setItem(adminTokenKey, data.access_token); if (data.admin) localStorage.setItem(adminProfileKey, JSON.stringify(data.admin)); refreshAdminHeader(); const msg = prf('saved'); setOutput(msg); showToast(msg, 'success'); } catch (err) { const msg = prf('failed').replace('{error}', err.message); setOutput(msg); showToast(msg, 'error'); } }
    async function loadInvitationCodeStatus() { try { const data = await api('/api/admin/invitation-codes/status'); invitationCodeRequired = !!data.invitation_code_required; renderInvitationCodeToggle(); } catch (err) { const msg = inv('statusLoadFailed', { error: err.message }); setOutput(msg); } }
    async function toggleInvitationCodeRequired() { try { const newVal = !invitationCodeRequired; const data = await api('/api/admin/invitation-codes/toggle', { method: 'POST', body: JSON.stringify({ required: newVal }) }); invitationCodeRequired = !!data.invitation_code_required; renderInvitationCodeToggle(); const msg = inv('toggleSuccess'); setOutput(msg); showToast(msg, 'success'); } catch (err) { const msg = inv('toggleFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    function renderInvitationCodeToggle() { const badge = document.getElementById('invCodeToggleBadge'); const btn = document.getElementById('invCodeToggleBtn'); if (badge) { badge.textContent = invitationCodeRequired ? inv('toggleEnabled') : inv('toggleDisabled'); badge.className = 'badge ' + (invitationCodeRequired ? 'ok' : 'warn'); } if (btn) { btn.textContent = invitationCodeRequired ? inv('toggleDisabled') : inv('toggleEnabled'); btn.className = invitationCodeRequired ? 'btn-danger' : 'btn-primary'; } }
    async function generateInvitationCodes() { try { const countInput = document.getElementById('invCodeCount'); const count = parseInt(countInput.value, 10) || 5; const data = await api('/api/admin/invitation-codes/generate', { method: 'POST', body: JSON.stringify({ count }) }); const msg = inv('generateSuccess', { count: String((data.codes || []).length) }); setOutput(msg); showToast(msg, 'success'); await loadInvitationCodes(); } catch (err) { const msg = inv('generateFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    async function loadInvitationCodes() { try { let path = '/api/admin/invitation-codes'; const params = []; if (invitationStatusFilter) params.push('status=' + encodeURIComponent(invitationStatusFilter)); if (invitationSearchTerm) params.push('search=' + encodeURIComponent(invitationSearchTerm)); if (params.length) path += '?' + params.join('&'); const data = await api(path); invitationCodesCache = data.codes || []; renderInvitationCodeList(); } catch (err) { const msg = inv('loadFailed', { error: err.message }); setOutput(msg); showToast(msg, 'error'); } }
    let invitationSearchTimer = null;
    function onInvitationSearch() { clearTimeout(invitationSearchTimer); invitationSearchTimer = setTimeout(() => { invitationSearchTerm = (document.getElementById('invCodeSearch')?.value || '').trim(); loadInvitationCodes(); }, 300); }
    function onInvitationFilterChange() { invitationStatusFilter = document.getElementById('invCodeFilter')?.value || ''; loadInvitationCodes(); }
    function renderInvitationCodeList() { const root = document.getElementById('invitationCodeList'); if (!root) return; if (!invitationCodesCache.length) { root.innerHTML = '<div class="hint">' + inv('emptyList') + '</div>'; return; } root.innerHTML = invitationCodesCache.map(c => { const isUsed = c.status === 'used'; const badgeClass = isUsed ? 'warn' : 'ok'; const statusText = isUsed ? inv('statusUsed') : inv('statusUnused'); const usedInfo = isUsed ? `<div class="item-meta">${inv('usedBy')}: ${c.used_by_email || '-'}</div><div class="item-meta">${inv('usedAt')}: ${c.used_at || '-'}</div>` : ''; const createdInfo = c.created_at ? `<div class="item-meta">${inv('createdAt')}: ${c.created_at}</div>` : ''; return `<div class="item" style="${isUsed ? 'opacity:.65' : ''}"><div class="item-head"><div><div class="item-title" style="font-family:Consolas,monospace;letter-spacing:.08em">${c.code}</div>${createdInfo}${usedInfo}</div><span class="badge ${badgeClass}">${statusText}</span></div></div>`; }).join(''); }
    async function refreshAll() { await Promise.all([loadCenterStatus(), loadBlockedEmails(), loadInvites(), loadBoundUsers(), loadMailConfig(), loadMachines()]); }
    applyI18n(); if (token()) { setAuthState(true); restoreTab(); refreshAll(); } else { setAuthState(false); refreshAuthStage(); }
  